%[text] Reads a text file containing a coded array of an image of size 64 x 64 and 32 intensity levels.
%[text] Each pixel is represented by an alphanumeric character ranging from 0-9 and A-V corresponding to 32 levels of gray.
%[text] 1\. Display the original image on screen
function coded_array = load_coded_image(filename)
% LOAD_CODED_IMAGE  Loads a coded image from a .txt file
%
% Usage:
%   coded_array = load_coded_image(filename)
%
% Input:
%   filename   — string, path to the .txt file containing the coded image
%                e.g. 'chromo.txt' or 'image2.txt'
%
% Output:
%   coded_array — 64x64 double matrix, intensity values 1..32
%                 1 = darkest (black), 32 = brightest (white)
%
% File format expected:
%   64x64 alphanumeric characters, one character per pixel
%   '0'-'9' map to intensity levels 1-10
%   'A'-'V' map to intensity levels 11-32
%   File is assumed to be stored row by row (standard image order)
%
% Example:
%   coded_array = load_coded_image('chromo.txt');
%   coded_array = load_coded_image('image2.txt');

% ----------------------------------------------------------
% Open file
% ----------------------------------------------------------
file_id = fopen(filename, 'r');
if file_id == -1
    error('Could not open file: %s — check the file path and name.', filename);
end

% ----------------------------------------------------------
% Read characters into a 64x64 matrix
% fscanf fills column by column — transpose is applied later
% ----------------------------------------------------------
format_spec = '%s';
size_array  = [64, 64];
coded_array = fscanf(file_id, format_spec, size_array);

% ----------------------------------------------------------
% Close file
% ----------------------------------------------------------
fclose(file_id);

% ----------------------------------------------------------
% Map alphanumeric characters to intensity levels 1..32
% '0'-'9' (10 chars) + 'A'-'V' (22 chars) = 32 levels total
% map is indexed by ASCII value of each character
% ----------------------------------------------------------
gray_levels = '0123456789ABCDEFGHIJKLMNOPQRSTUV';
map         = zeros(1, 128);
map(gray_levels) = 1:length(gray_levels);

coded_array = map(coded_array);

% ----------------------------------------------------------
% Validate — catch any unmapped or unexpected characters
% ----------------------------------------------------------
if any(coded_array(:) == 0)
    warning('coded_array contains unmapped values (0). Check "%s" for unexpected whitespace or invalid characters.', filename);
end

% ----------------------------------------------------------
% Transpose to correct row/column orientation
% fscanf fills column-major — transpose restores row-major layout
% ----------------------------------------------------------
coded_array = coded_array';

fprintf('Loaded "%s" — size: %dx%d — intensity range: [%d, %d]\n', ...
    filename, size(coded_array,1), size(coded_array,2), ...
    min(coded_array(:)), max(coded_array(:)));

end
%[text] 
% ----------------------------------------------------------
% Display
% ----------------------------------------------------------

% Load image
coded_array = load_coded_image('data\charact1.txt'); %[output:5a13c9a1]

figure(12) %[output:84a2c263]

subplot(2,1,1) %[output:84a2c263]
imshow(coded_array, DisplayRange=[1 32]) %[output:84a2c263]
title('Raw Coded Image') %[output:84a2c263]

subplot(2,1,2) %[output:84a2c263]
histogram(coded_array(:), 'BinEdges', 0.5:1:32.5) %[output:84a2c263]
xlabel('Intensity Level') %[output:84a2c263]
ylabel('Frequency') %[output:84a2c263]
title('Intensity Histogram') %[output:84a2c263]
xlim([0 33]) %[output:84a2c263]
%[text] 2\. Threshold the image and convert it into binary image (using Otsu's Method)
%[text] Referenced from page 747-751 Chapter 10.3 "Digital Image Processing 4e - R. C. Gonzales, R. E. Woods" and [https://en.wikipedia.org/wiki/Otsu%27s\_method](https://en.wikipedia.org/wiki/Otsu%27s_method)
%[text] \[potential alternative: Sauvola Method\]
% ==========================================================
% Otsu's Method — Automatic Image Thresholding
% Referenced: Gonzalez & Woods, Digital Image Processing 4e
%             Chapter 10.3, pp. 747-751
%             and Wikipedia: Otsu's method
%
% Input:  coded_array — grayscale image, intensity levels 1..32
%                       higher value = brighter (32 = white)
% Output: T           — binary image (0 = black, 1 = white)
% ==========================================================

function [T, threshold] = otsu_threshold(coded_array)
% OTSU_THRESHOLD  Automatic image thresholding using Otsu's Method
%
% Usage:
%   [T, threshold] = otsu_threshold(coded_array)
%
% Input:
%   coded_array — grayscale image matrix with intensity levels 1..32
%                 1 = darkest (black), 32 = brightest (white)
%
% Outputs:
%   T         — binary image matrix (0 = dark/foreground, 1 = bright/background)
%               pixels with intensity <= threshold → 0 (black)
%               pixels with intensity >  threshold → 1 (white)
%   threshold — optimal threshold level k* found by Otsu's method
%
% Referenced:
%   Gonzalez & Woods, Digital Image Processing 4e
%   Chapter 10.3, pp. 747-751
%   and Wikipedia: Otsu's method
%
% Example:
%   coded_array        = load_coded_image('chromo.txt');
%   [T, threshold]     = otsu_threshold(coded_array);
%   [T2, threshold2]   = otsu_threshold(coded_array2);

L = 32;
[rows, cols] = size(coded_array);
N_total      = rows * cols;

% ----------------------------------------------------------
% Step 1 — Count pixels at each intensity level
% ----------------------------------------------------------
counts = zeros(1, L);
for r = 1:rows
    for c = 1:cols
        k          = coded_array(r, c);
        counts(k)  = counts(k) + 1;
    end
end

% ----------------------------------------------------------
% Step 2 — Normalised histogram — probability of each level
% ----------------------------------------------------------
p = counts / N_total;

% ----------------------------------------------------------
% Step 3 — Cumulative probability P1(k)
% P1(k) = probability of intensity <= k
% ----------------------------------------------------------
p1 = zeros(1, L);
for k = 1:L
    for i = 1:k
        p1(k) = p1(k) + p(i);
    end
end

% ----------------------------------------------------------
% Step 4 — Cumulative mean mk
% mk(k) = sum of (intensity * probability) for levels 1..k
% ----------------------------------------------------------
mk = zeros(1, L);
for k = 1:L
    for i = 1:k
        mk(k) = mk(k) + (i * p(i));
    end
end

% ----------------------------------------------------------
% Step 5 — Global mean mg
% ----------------------------------------------------------
mg = mk(L);

% ----------------------------------------------------------
% Step 6 — Global variance var_g
% ----------------------------------------------------------
var_g = 0;
for r = 1:rows
    for c = 1:cols
        var_g = var_g + (coded_array(r, c) - mg)^2;
    end
end
var_g = var_g / N_total;

% ----------------------------------------------------------
% Step 7 — Between-class variance var_b for each threshold k
% Guard against division by zero at extremes (p1 = 0 or 1)
% ----------------------------------------------------------
var_b = zeros(1, L);
for k = 1:L
    denom = p1(k) * (1 - p1(k));
    if denom > 0
        var_b(k) = (mg * p1(k) - mk(k))^2 / denom;
    else
        var_b(k) = 0;
    end
end

% ----------------------------------------------------------
% Step 8 — Threshold effectiveness measure eta
% ----------------------------------------------------------
eff_thres = var_b / var_g;

% ----------------------------------------------------------
% Step 9 — Optimal threshold k* — maximum between-class variance
% ----------------------------------------------------------
[max_var_b, threshold] = max(var_b);

fprintf('Otsu threshold k* = %d | max var_b = %.4f | eta = %.4f\n', ...
         threshold, max_var_b, eff_thres(threshold));

% ----------------------------------------------------------
% Step 10 — Apply threshold to produce binary image T
% Pixels > threshold → white (1) background
% Pixels <= threshold → black (0) foreground
% ----------------------------------------------------------
T = zeros(rows, cols);
for r = 1:rows
    for c = 1:cols
        if coded_array(r, c) > threshold
            T(r, c) = 1;
        else
            T(r, c) = 0;
        end
    end
end

end
%[text] 
% ----------------------------------------------------------
% Display
% ----------------------------------------------------------

[T, threshold] = otsu_threshold(coded_array); %[output:7d3f0c55]

figure(13) %[output:395eb15e]

subplot(1,2,1) %[output:395eb15e]
imshow(coded_array, DisplayRange=[1 32]) %[output:395eb15e]
title('Raw Coded Image') %[output:395eb15e]

subplot(1,2,2) %[output:395eb15e]
imshow(T) %[output:395eb15e]
title(sprintf('Otsu Threshold k* = %d', threshold)) %[output:395eb15e]
%[text] 3\. Determine a one-pixel thin image of the objects (using Zhang-Suen thinning algorithm to erode image)
%[text] [https://rosettacode.org/wiki/Zhang-Suen\_thinning\_algorithm](https://rosettacode.org/wiki/Zhang-Suen_thinning_algorithm)
%[text] \[potential alternative: Guo-Hall Algorithm\]
function thinned = zhang_suen(T, foreground)
% ZHANG_SUEN  Zhang-Suen thinning algorithm
%
% Usage:
%   thinned = zhang_suen(T, foreground)
%
% Inputs:
%   T          — binary image matrix (values 0 and 1)
%   foreground — value that represents the foreground object to be thinned
%                0 : foreground is black
%                1 : foreground is white
%
% Output:
%   thinned    — thinned binary image, same convention as input T
%                (foreground and background values are preserved as given)
%
% Example:
%   thinned = zhang_suen(T, 0)  % black foreground
%   thinned = zhang_suen(T, 1)  % white foreground

% ----------------------------------------------------------
% Normalise to algorithm convention: foreground = 0 (black)
% If the input uses white (1) as foreground, flip it first
% ----------------------------------------------------------
if foreground == 1
    img = 1 - T;   % flip so foreground becomes 0
else
    img = double(T);
end

img           = double(img);
[rows, cols]  = size(img);
changed       = true;
iter          = 0;

while changed

    iter = iter + 1;
    prev = img;

    % ------------------------------------------------------
    % Pass 1 — South-East boundary removal
    % ------------------------------------------------------
    
    marker1 = false(rows, cols);

    for r = 2:rows-1
        for c = 2:cols-1
            
            % Neighbor layout (clockwise from top):
            %
            %   P9 | P2 | P3
            %   ───────────
            %   P8 | P1 | P4
            %   ───────────
            %   P7 | P6 | P5

            P1 = img(r,   c  );
            P2 = img(r-1, c  );
            P3 = img(r-1, c+1);
            P4 = img(r,   c+1);
            P5 = img(r+1, c+1);
            P6 = img(r+1, c  );
            P7 = img(r+1, c-1);
            P8 = img(r,   c-1);
            P9 = img(r-1, c-1);

            % B(P): count black (0) neighbors — foreground
            B = (P2==0) + (P3==0) + (P4==0) + (P5==0) + ...
                (P6==0) + (P7==0) + (P8==0) + (P9==0);

            % A(P): count 1->0 transitions clockwise
            nb = [P2, P3, P4, P5, P6, P7, P8, P9, P2];
            A  = 0;
            for k = 1:8
                if nb(k) == 1 && nb(k+1) == 0
                    A = A + 1;
                end
            end

            if P1 == 0              && ...
               B >= 2 && B <= 6     && ...
               A == 1               && ...
               (P2 + P4 + P6) > 0   && ...
               (P4 + P6 + P8) > 0
                marker1(r, c) = true;
            end

        end
    end

    img(marker1) = 1;   % delete marked pixels

    % ------------------------------------------------------
    % Pass 2 — North-West boundary removal
    % ------------------------------------------------------
    marker2 = false(rows, cols);

    for r = 2:rows-1
        for c = 2:cols-1

            P1 = img(r,   c  );
            P2 = img(r-1, c  );
            P3 = img(r-1, c+1);
            P4 = img(r,   c+1);
            P5 = img(r+1, c+1);
            P6 = img(r+1, c  );
            P7 = img(r+1, c-1);
            P8 = img(r,   c-1);
            P9 = img(r-1, c-1);

            B = (P2==0) + (P3==0) + (P4==0) + (P5==0) + ...
                (P6==0) + (P7==0) + (P8==0) + (P9==0);

            nb = [P2, P3, P4, P5, P6, P7, P8, P9, P2];
            A  = 0;
            for k = 1:8
                if nb(k) == 1 && nb(k+1) == 0
                    A = A + 1;
                end
            end

            if P1 == 0              && ...
               B >= 2 && B <= 6     && ...
               A == 1               && ...
               (P2 + P4 + P8) > 0   && ...
               (P2 + P6 + P8) > 0
                marker2(r, c) = true;
            end

        end
    end

    img(marker2) = 1;   % delete marked pixels

    changed = ~isequal(img, prev);
    fprintf('Iteration %d | Pass1 removed: %d | Pass2 removed: %d\n', ...
             iter, sum(marker1(:)), sum(marker2(:)));

end

fprintf('Thinning complete in %d iterations.\n', iter);

% ----------------------------------------------------------
% Restore original convention
% If input had white foreground, flip result back
% ----------------------------------------------------------
if foreground == 1
    thinned = 1 - img;
else
    thinned = img;
end

end
%[text] 
% ----------------------------------------------------------
% Display
% ----------------------------------------------------------

thinned = zhang_suen(T, 1); %[output:6194e691]

figure(14) %[output:6b699b10]

subplot(1,2,1) %[output:6b699b10]
imshow(T) %[output:6b699b10]
title(sprintf('Otsu Threshold k* = %d', threshold)) %[output:6b699b10]

subplot(1,2,2) %[output:6b699b10]
imshow(thinned) %[output:6b699b10]
title('Zhang-Suen Thinned Image') %[output:6b699b10]
%[text] 4\. Determine the outline(s)
%[text] Thresholding based on the boundary to determine the outline
%[text] The method proceeds by scanning the given image 𝑓(𝑥,𝑦) of size 𝑁 by 𝑁.  A change in gray level from one band to the other denotes the presence of boundaries.
%[text] Pass 1 and 2 are to detect changes in the 𝑦 and 𝑥 directions, respectively. The combination of the results of the two passes will yield the boundary of the objects in the image.
%[text] Referenced from p29-33 "Thresholding based on the boundary, Chapter 3 - Binary Image and Color Image Processing, ME5405 Lecture Notes"
function bound = boundary_detection(T, foreground)
% BOUNDARY_DETECTION  Two-pass row-column boundary detection
%
% Usage:
%   bound = boundary_detection(T, foreground)
%
% Inputs:
%   T          — binary image matrix (values 0 and 1)
%   foreground — value that represents the foreground object
%                0 : foreground is black, background is white
%                1 : foreground is white, background is black
%
% Output:
%   bound      — boundary image, same convention as input T
%                edge pixels carry the foreground value
%                non-edge pixels carry the background value
%
% Example:
%   bound = boundary_detection(T, 0)  % black foreground
%   bound = boundary_detection(T, 1)  % white foreground

% ----------------------------------------------------------
% Normalise to internal convention: foreground = 0 (black)
% LE = 0 (edge), LB = 1 (background)
% If input uses white foreground, flip before processing
% ----------------------------------------------------------
if foreground == 1
    img = 1 - T;
else
    img = double(T);
end

img          = double(img);
[rows, cols] = size(img);

LE = 0;   % edge pixel value
LB = 1;   % background pixel value

% Initialise intermediate images to LB (all background)
% First row and column have no prior neighbor — correctly stays LB
bound_inter1 = ones(rows, cols);   % g1 — horizontal transitions (Pass 1)
bound_inter2 = ones(rows, cols);   % g2 — vertical transitions   (Pass 2)

% ----------------------------------------------------------
% Pass 1 — scan each row, detect transitions in y direction
% Compare f(r,c) with left neighbor f(r, c-1)
% g1(r,c) = LE if different bands, LB otherwise
% ----------------------------------------------------------
for r = 2:rows
    for c = 2:cols
        if img(r,c) ~= img(r, c-1)
            bound_inter1(r,c) = LE;
        else
            bound_inter1(r,c) = LB;
        end
    end
end

% ----------------------------------------------------------
% Pass 2 — scan each column, detect transitions in x direction
% Compare f(r,c) with upper neighbor f(r-1, c)
% g2(r,c) = LE if different bands, LB otherwise
% ----------------------------------------------------------
for r = 2:rows
    for c = 2:cols
        if img(r,c) ~= img(r-1, c)
            bound_inter2(r,c) = LE;
        else
            bound_inter2(r,c) = LB;
        end
    end
end

% ----------------------------------------------------------
% Combination — equation (9)
% g(r,c) = LE if g1(r,c) = LE OR g2(r,c) = LE
%         = LB otherwise
% ----------------------------------------------------------
bound_img = ones(rows, cols);   % initialise to all background

for r = 1:rows
    for c = 1:cols
        if bound_inter1(r,c) == LE || bound_inter2(r,c) == LE
            bound_img(r,c) = LE;
        else
            bound_img(r,c) = LB;
        end
    end
end

% ----------------------------------------------------------
% Restore original convention
% If input had white foreground, flip result back
% ----------------------------------------------------------
if foreground == 1
    bound = 1 - bound_img;
else
    bound = bound_img;
end

end
%[text] 
% ----------------------------------------------------------
% Display
% ----------------------------------------------------------

bound = boundary_detection(T, 1);

figure(15) %[output:79a4c833]

subplot(1,2,1) %[output:79a4c833]
imshow(T) %[output:79a4c833]
title(sprintf('Otsu Threshold k* = %d', threshold)) %[output:79a4c833]

subplot(1,2,2) %[output:79a4c833]
imshow(bound) %[output:79a4c833]
title('Boundary Detection') %[output:79a4c833]
%[text] 5\. Label the different objects (using two-pass algorithm)
%[text] Referenced from p41-46 "Connected Components Operators, Chapter 3 - Binary Image and Color Image Processing, ME5405 Lecture Notes" and [https://en.wikipedia.org/wiki/Connected-component\_labeling\#Two-pass](https://en.wikipedia.org/wiki/Connected-component_labeling#Two-pass) and [https://en.wikipedia.org/wiki/Hoshen%E2%80%93Kopelman\_algorithm](https://en.wikipedia.org/wiki/Hoshen%E2%80%93Kopelman_algorithm)
function [label_matrix, num_components] = ccl_two_pass(T, foreground)
% CCL_TWO_PASS  Two-Pass Connected-Component Labeling
%
% Usage:
%   [label_matrix, num_components] = ccl_two_pass(T, foreground)
%
% Inputs:
%   T          — binary image matrix (values 0 and 1)
%   foreground — value that represents the foreground objects to be labeled
%                0 : foreground is black, background is white
%                1 : foreground is white, background is black
%
% Outputs:
%   label_matrix   — integer matrix, each unique positive integer
%                    corresponds to one connected component
%                    0 everywhere means background (no component)
%   num_components — total number of connected components found
%
% Connectivity: 8-connected (NW, N, NE, W neighbors checked)
%
% Example:
%   [labels, n] = ccl_two_pass(T, 0)  % black foreground
%   [labels, n] = ccl_two_pass(T, 1)  % white foreground

% ----------------------------------------------------------
% Normalise to internal convention: foreground = 0 (black)
% The algorithm checks (img == 0) to identify foreground pixels
% If input uses white foreground, flip before processing
% ----------------------------------------------------------
if foreground == 1
    img = 1 - T;
else
    img = double(T);
end

img          = double(img);
[rows, cols] = size(img);

% Label matrix initialised to 0 (background — no label assigned)
label_matrix = zeros(rows, cols);
max_labels   = rows * cols;
parent       = 1:max_labels;   % each label is its own root initially
NextLabel    = 0;

% ==========================================================
% PASS 1 — Provisional labeling and equivalence recording
% Scan left to right, top to bottom (raster order)
% 8-connectivity: check NW, N, NE, W neighbors
% ==========================================================

for r = 1:rows
    for c = 1:cols

        if img(r, c) == 0   % foreground pixel (black in internal convention)

            % --- Collect labels of visited neighbors ---
            neighbor_labels = [];

            if c > 1 && label_matrix(r, c-1) > 0                   % West
                neighbor_labels(end+1) = label_matrix(r, c-1);
            end
            if r > 1 && c > 1 && label_matrix(r-1, c-1) > 0        % North-West
                neighbor_labels(end+1) = label_matrix(r-1, c-1);
            end
            if r > 1 && label_matrix(r-1, c) > 0                    % North
                neighbor_labels(end+1) = label_matrix(r-1, c);
            end
            if r > 1 && c < cols && label_matrix(r-1, c+1) > 0     % North-East
                neighbor_labels(end+1) = label_matrix(r-1, c+1);
            end

            if isempty(neighbor_labels)
                % No labeled neighbors — create new label
                NextLabel         = NextLabel + 1;
                parent(NextLabel) = NextLabel;
                label_matrix(r, c) = NextLabel;

            else
                % Resolve each neighbor to its root, find minimum
                min_label = inf;
                for k = 1:length(neighbor_labels)
                    root = neighbor_labels(k);
                    while parent(root) ~= root
                        root = parent(root);
                    end
                    if root < min_label
                        min_label = root;
                    end
                end

                % Assign minimum root label to current pixel
                label_matrix(r, c) = min_label;

                % Union all neighbor roots to min_label
                for k = 1:length(neighbor_labels)
                    root = neighbor_labels(k);
                    while parent(root) ~= root
                        root = parent(root);
                    end
                    if root ~= min_label
                        parent(root) = min_label;
                    end
                end

            end

        end

    end
end

fprintf('Pass 1 complete. Provisional labels assigned: %d\n', NextLabel);

% ==========================================================
% BETWEEN PASSES — Resolve equivalences, renumber labels
% ==========================================================

% Fully flatten all chains in parent table to their root
for L = 1:NextLabel
    root = L;
    while parent(root) ~= root
        root = parent(root);
    end
    parent(L) = root;
end

% Assign sequential component numbers to each unique root
remap          = zeros(1, NextLabel);
num_components = 0;
for L = 1:NextLabel
    if parent(L) == L
        num_components = num_components + 1;
        remap(L)       = num_components;
    end
end

% Build final label lookup
final_label = zeros(1, NextLabel);
for L = 1:NextLabel
    final_label(L) = remap(parent(L));
end

fprintf('Equivalences resolved. Components found: %d\n', num_components);

% ==========================================================
% PASS 2 — Replace provisional labels with final labels
% ==========================================================

for r = 1:rows
    for c = 1:cols
        if label_matrix(r, c) > 0
            label_matrix(r, c) = final_label(label_matrix(r, c));
        end
    end
end

fprintf('Pass 2 complete. Labeling finished.\n');
fprintf('Total connected components: %d\n', num_components);

end
%[text] 
% ----------------------------------------------------------
% Display
% ----------------------------------------------------------

[label_matrix, num_components] = ccl_two_pass(T, 1); %[output:237e48af]

display_matrix = double(label_matrix);
display_matrix(label_matrix == 0) = NaN;

figure(16) %[output:90e3ce8a]

subplot(1,2,1) %[output:90e3ce8a]
imshow(T) %[output:90e3ce8a]
title(sprintf('Otsu Threshold k* = %d', threshold)) %[output:90e3ce8a]

subplot(1,2,2) %[output:90e3ce8a]
imagesc(display_matrix, 'AlphaData', ~isnan(display_matrix)) %[output:90e3ce8a]
set(gca, 'Color', 'white')
colormap(jet) %[output:90e3ce8a]
colorbar %[output:90e3ce8a]
title(sprintf('Labeling — %d regions found', num_components)) %[output:90e3ce8a]
axis image off %[output:90e3ce8a]
%[text] 6\. Arrange the characters in one line with the sequence
function arranged = arrange_components(T, label_matrix, component_sequence, background, spacing, padding)
% ARRANGE_COMPONENTS  Extracts and arranges CCL components in a specified sequence
%
% Usage:
%   arranged = arrange_components(T, label_matrix, component_sequence)
%   arranged = arrange_components(T, label_matrix, component_sequence, background)
%   arranged = arrange_components(T, label_matrix, component_sequence, background, spacing)
%   arranged = arrange_components(T, label_matrix, component_sequence, background, spacing, padding)
%
% Inputs:
%   T                  — binary image (values 0 and 1)
%   label_matrix       — integer label matrix from ccl_two_pass
%                        0 = background, 1..n = component labels
%   component_sequence — row vector of component IDs in desired output order
%                        e.g. [1 4 5] produces components 1, 4, 5 left to right
%   background         — (optional) pixel value used for background, spacing,
%                        and padding. Should match image convention:
%                        1 : background is white (foreground is black) — default
%                        0 : background is black (foreground is white)
%   spacing            — (optional) number of background-colored pixels between
%                        characters. Default: 3
%   padding            — (optional) number of background-colored pixels added
%                        around each character crop on all four sides.
%                        Default: 2
%
% Output:
%   arranged           — binary image with selected components arranged
%                        in a single row in the specified sequence
%                        empty space filled with background color
%
% Example:
%   % Minimal call — all optional args use defaults
%   arranged = arrange_components(T, label_matrix, [1 4 6]);
%
%   % Black background, white foreground, default spacing and padding
%   arranged = arrange_components(T, label_matrix, [4 5 1 2 3 6], 0);
%
%   % White background, custom spacing
%   arranged = arrange_components(T, label_matrix, [4 5 1 2 3 6], 1, 5);
%
%   % Full specification
%   arranged = arrange_components(T, label_matrix, [4 5 1 2 3 6], 1, 5, 4);

% ----------------------------------------------------------
% Handle optional arguments
% ----------------------------------------------------------
if nargin < 4 || isempty(background)
    background = 1;   % default: white background, black foreground
end
if nargin < 5 || isempty(spacing)
    spacing = 3;
end
if nargin < 6 || isempty(padding)
    padding = 2;
end

num_selected = length(component_sequence);
[rows, cols] = size(label_matrix);

% ----------------------------------------------------------
% Step 1 — Extract bounding box for each selected component
% ----------------------------------------------------------
r_min = zeros(1, num_selected);
r_max = zeros(1, num_selected);
c_min = zeros(1, num_selected);
c_max = zeros(1, num_selected);

for idx = 1:num_selected

    k = component_sequence(idx);

    if ~any(label_matrix(:) == k)
        error('Component ID %d not found in label_matrix.', k);
    end

    r_min(idx) = rows;
    r_max(idx) = 1;
    c_min(idx) = cols;
    c_max(idx) = 1;

    for r = 1:rows
        for c = 1:cols
            if label_matrix(r, c) == k
                if r < r_min(idx), r_min(idx) = r; end
                if r > r_max(idx), r_max(idx) = r; end
                if c < c_min(idx), c_min(idx) = c; end
                if c > c_max(idx), c_max(idx) = c; end
            end
        end
    end

end

% ----------------------------------------------------------
% Step 2 — Compute padded bounding box extents
% Clamped to image boundaries to avoid out-of-bounds indexing
% ----------------------------------------------------------
r_min_pad = max(r_min - padding, 1);
r_max_pad = min(r_max + padding, rows);
c_min_pad = max(c_min - padding, 1);
c_max_pad = min(c_max + padding, cols);

crop_heights = r_max_pad - r_min_pad + 1;
crop_widths  = c_max_pad - c_min_pad + 1;

fprintf('Component bounding boxes (padding = %d):\n', padding);
for idx = 1:num_selected
    fprintf('  Component %d — rows %d:%d cols %d:%d — size %dx%d\n', ...
        component_sequence(idx), ...
        r_min_pad(idx), r_max_pad(idx), ...
        c_min_pad(idx), c_max_pad(idx), ...
        crop_heights(idx), crop_widths(idx));
end

% ----------------------------------------------------------
% Step 3 — Compute output canvas dimensions
% ----------------------------------------------------------
canvas_height = max(crop_heights);
canvas_width  = sum(crop_widths) + spacing * (num_selected - 1);

fprintf('Canvas: %d x %d | background = %d | spacing = %d | padding = %d\n', ...
    canvas_height, canvas_width, background, spacing, padding);

% ----------------------------------------------------------
% Step 4 — Initialise canvas to background color
% ----------------------------------------------------------
arranged = background * ones(canvas_height, canvas_width);

% ----------------------------------------------------------
% Step 5 — Paste each padded component crop onto canvas
% ----------------------------------------------------------
col_offset = 1;

for idx = 1:num_selected

    k = component_sequence(idx);

    % Crop from T using padded bounding box
    crop = T(r_min_pad(idx):r_max_pad(idx), ...
              c_min_pad(idx):c_max_pad(idx));

    % Centre vertically on canvas
    row_offset = floor((canvas_height - crop_heights(idx)) / 2) + 1;

    % Paste onto canvas
    arranged(row_offset : row_offset + crop_heights(idx) - 1, ...
             col_offset : col_offset + crop_widths(idx)  - 1) = crop;

    fprintf('  Placed component %d at rows %d:%d cols %d:%d\n', ...
        k, ...
        row_offset, row_offset + crop_heights(idx) - 1, ...
        col_offset, col_offset + crop_widths(idx)  - 1);

    col_offset = col_offset + crop_widths(idx) + spacing;

end

end
%[text] 
% ----------------------------------------------------------
% Display
% ----------------------------------------------------------

% "AB123C"  →  components 4, 5, 1, 2, 3, 6
arranged = arrange_components(T, label_matrix, [4 5 1 2 3 6], 0); %[output:98e7986a]

% Display result
figure(17) %[output:17948cb9]

subplot(1,2,1) %[output:17948cb9]
imshow(arranged) %[output:17948cb9]
title('Arranged Characters') %[output:17948cb9]
%[text] 7\. Rotate the output image from Step 6 about its center by 30 degrees.
%[text] Using nearest-neighbour interpolation and inverse/backwards mapping.
function rotated = rotate_image(T, angle_deg, direction, background)
% ROTATE_IMAGE  Rotates a binary image about its center
%               Output canvas is sized to contain the entire rotated image
%
% Uses backward mapping with nearest neighbor interpolation.
% Output is binary — same values (0 and 1) as input.
%
% Usage:
%   rotated = rotate_image(T, angle_deg)
%   rotated = rotate_image(T, angle_deg, direction)
%   rotated = rotate_image(T, angle_deg, direction, background)
%
% Inputs:
%   T          — binary image matrix (values 0 and 1)
%   angle_deg  — rotation angle in degrees (positive value)
%   direction  — (optional) rotation direction:
%                'cw'  : clockwise (default)
%                'ccw' : counter-clockwise
%   background — (optional) pixel value for out-of-bounds regions
%                1 : white background (default)
%                0 : black background
%
% Output:
%   rotated    — rotated binary image, expanded canvas size to fully
%                contain the rotated image with no clipping
%
% Example:
%   rotated = rotate_image(T, 30, 'cw', 1);
%   rotated = rotate_image(T, 30, 'ccw', 0);
%   rotated = rotate_image(T, 30);

% ----------------------------------------------------------
% Handle optional arguments
% ----------------------------------------------------------
if nargin < 3 || isempty(direction)
    direction = 'cw';
end
if nargin < 4 || isempty(background)
    background = 1;
end

% ----------------------------------------------------------
% Validate direction input
% ----------------------------------------------------------
if ~strcmp(direction, 'cw') && ~strcmp(direction, 'ccw')
    error('direction must be ''cw'' (clockwise) or ''ccw'' (counter-clockwise).');
end

% ----------------------------------------------------------
% Convert angle to radians with direction sign convention
% Negative angle → clockwise in image coordinates (y axis down)
% Positive angle → counter-clockwise in image coordinates
% ----------------------------------------------------------
if strcmp(direction, 'cw')
    theta = -deg2rad(angle_deg);
else
    theta =  deg2rad(angle_deg);
end

% ----------------------------------------------------------
% Input image dimensions and center
% ----------------------------------------------------------
[rows_in, cols_in] = size(T);
cx_in = (cols_in + 1) / 2;
cy_in = (rows_in + 1) / 2;

% ----------------------------------------------------------
% Compute output canvas size to contain entire rotated image
%
% Rotate all four corners of the input image and find the
% bounding box of those rotated corners. The canvas is sized
% to exactly fit this bounding box.
%
% The four corners in center-origin coordinates are:
%   top-left:     (-cx_in+0.5, -cy_in+0.5)
%   top-right:    ( cx_in-0.5, -cy_in+0.5)
%   bottom-left:  (-cx_in+0.5,  cy_in-0.5)
%   bottom-right: ( cx_in-0.5,  cy_in-0.5)
% ----------------------------------------------------------
cos_t = cos(theta);
sin_t = sin(theta);

% Corner offsets from center in center-origin coordinates
half_w = cols_in / 2;
half_h = rows_in / 2;

corners_x = [-half_w,  half_w, -half_w,  half_w];
corners_y = [-half_h, -half_h,  half_h,  half_h];

% Rotate each corner using forward rotation matrix
rotated_corners_x = cos_t * corners_x - sin_t * corners_y;
rotated_corners_y = sin_t * corners_x + cos_t * corners_y;

% Bounding box of rotated corners gives required canvas size
% ceil ensures the canvas fully contains all rotated content
cols_out = ceil(max(rotated_corners_x) - min(rotated_corners_x));
rows_out = ceil(max(rotated_corners_y) - min(rotated_corners_y));

% Center of the output canvas
cx_out = (cols_out + 1) / 2;
cy_out = (rows_out + 1) / 2;

fprintf('Input size:  %d x %d\n', rows_in, cols_in);
fprintf('Output size: %d x %d\n', rows_out, cols_out);

% ----------------------------------------------------------
% Inverse rotation components for backward mapping
% R_inv is rotation by -theta (transpose of forward R)
% ----------------------------------------------------------
cos_inv =  cos_t;    % cos(-theta) =  cos(theta)
sin_inv = -sin_t;    % sin(-theta) = -sin(theta)

% ----------------------------------------------------------
% Initialise output canvas to background color
% ----------------------------------------------------------
rotated = background * ones(rows_out, cols_out);

% ----------------------------------------------------------
% Backward mapping
%
% For each pixel (r,c) in the OUTPUT canvas:
%
%   Step 1: Translate from output canvas coordinates to
%           center-origin using OUTPUT center
%
%   Step 2: Apply inverse rotation to find source location
%           in center-origin coordinates
%
%   Step 3: Translate from center-origin back to INPUT
%           image coordinates using INPUT center
%
%   Step 4: Nearest neighbor — round to closest integer
%
%   Step 5: Bounds check — copy from input if inside bounds,
%           otherwise leave as background
% ----------------------------------------------------------
for r = 1:rows_out
    for c = 1:cols_out

        % Step 1 — translate to center-origin using output center
        xc = c - cx_out;
        yc = r - cy_out;

        % Step 2 — apply inverse rotation
        x_src_c =  cos_inv * xc + sin_inv * yc;
        y_src_c = -sin_inv * xc + cos_inv * yc;

        % Step 3 — translate back using INPUT image center
        x_src = x_src_c + cx_in;
        y_src = y_src_c + cy_in;

        % Step 4 — nearest neighbor interpolation
        c_src = round(x_src);
        r_src = round(y_src);

        % Step 5 — bounds check and pixel assignment
        if r_src >= 1 && r_src <= rows_in && ...
           c_src >= 1 && c_src <= cols_in
            rotated(r, c) = T(r_src, c_src);
        end

    end
end

fprintf('Rotation complete: %g degrees %s | background = %d\n', ...
    angle_deg, direction, background);

end
%[text] 
% ----------------------------------------------------------
% Display
% ----------------------------------------------------------

% Rotate 30 degrees clockwise, white background
rotated = rotate_image(arranged, 30, 'cw', 1); %[output:99f8e662]

subplot(1,2,2) %[output:17948cb9]
imshow(rotated) %[output:17948cb9]
title('Rotated 30° Clockwise') %[output:17948cb9]

